function m(o,r,t){const n=s(o),e=s(r),c=[];for(let a=0;a<t;a++){const u=Math.round(n.r+(e.r-n.r)*(a/(t-1))),i=Math.round(n.g+(e.g-n.g)*(a/(t-1))),l=Math.round(n.b+(e.b-n.b)*(a/(t-1))),d=g(u,i,l);c.push(d)}return c}function s(o){o=o.replace(/^#/,"");const r=parseInt(o,16),t=r>>16&255,n=r>>8&255,e=r&255;return{r:t,g:n,b:e}}function g(o,r,t){return`#${((1<<24)+(o<<16)+(r<<8)+t).toString(16).slice(1)}`}function f(o,r="medium",t="en"){const n=new Date(o.replaceAll("-","/"));return new Intl.DateTimeFormat(t,{dateStyle:r}).format(n)}export{f,m as g};
